insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000002001','30000000-0000-0000-0000-000000000020',1,$p$Dijo que…: say vs tell y backshift$p$,$p$Dijo que…: say vs tell y backshift$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002002','30000000-0000-0000-0000-000000000020',2,$p$Me preguntó si…: preguntas indirectas$p$,$p$Me preguntó si…: preguntas indirectas$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002003','30000000-0000-0000-0000-000000000020',3,$p$Me pidió que…: órdenes y peticiones$p$,$p$Me pidió que…: órdenes y peticiones$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002004','30000000-0000-0000-0000-000000000020',4,$p$Ayer→aquel día: cambios de tiempo y lugar$p$,$p$Ayer→aquel día: cambios de tiempo y lugar$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002005','30000000-0000-0000-0000-000000000020',5,$p$🏁 Checkpoint Unidad 20$p$,$p$El estilo indirecto cuenta lo que alguien dijo sin repetirlo textualmente. Recuerda 'say' (sin objeto: she said that...) frente a 'tell' (con persona: she told me that...), el backshift de tiempos (is->was, will->would, can->could) y los cambios de pronombres. En preguntas indirectas se usa 'asked if/whether' o 'asked what/where' con orden de afirmación (sin do/did), y para órdenes y peticiones 'told/asked somebody to do'. Las expresiones de tiempo y lugar cambian: today->that day, yesterday->the day before, here->there.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
