insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000002101','30000000-0000-0000-0000-000000000021',1,$p$Se hace así: la pasiva en presente$p$,$p$Se hace así: la pasiva en presente$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002102','30000000-0000-0000-0000-000000000021',2,$p$Fue hecho: la pasiva en pasado$p$,$p$Fue hecho: la pasiva en pasado$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002103','30000000-0000-0000-0000-000000000021',3,$p$Por quién: el agente con by$p$,$p$Por quién: el agente con by$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002104','30000000-0000-0000-0000-000000000021',4,$p$Lo mandé hacer: have something done$p$,$p$Lo mandé hacer: have something done$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002105','30000000-0000-0000-0000-000000000021',5,$p$🏁 Checkpoint Unidad 21$p$,$p$En esta unidad dominas la voz pasiva: "be" + participio para hablar de procesos y noticias sin nombrar quién actúa. La usas en presente (The coffee is grown in Brazil) y en pasado (The bridge was built in 1920), añades el agente con "by" cuando importa (The film was directed by a Spaniard) y aprendes el causativo "have something done" para decir que mandas hacer algo (I had my car repaired).$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
