insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000002201','30000000-0000-0000-0000-000000000022',1,$p$Si lo hubiera sabido: tercer condicional$p$,$p$Si lo hubiera sabido: tercer condicional$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002202','30000000-0000-0000-0000-000000000022',2,$p$Resultados de hoy por el ayer: condicionales mixtos$p$,$p$Resultados de hoy por el ayer: condicionales mixtos$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002203','30000000-0000-0000-0000-000000000022',3,$p$Ojalá lo hubiera hecho: wish / if only$p$,$p$Ojalá lo hubiera hecho: wish / if only$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002204','30000000-0000-0000-0000-000000000022',4,$p$Repaso: condicionales 1.º, 2.º y 3.º en contexto$p$,$p$Repaso: condicionales 1.º, 2.º y 3.º en contexto$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002205','30000000-0000-0000-0000-000000000022',5,$p$🏁 Checkpoint Unidad 22$p$,$p$En esta unidad dominas el tercer condicional (If + past perfect, would have + participio) para hablar de situaciones pasadas irreales y sus consecuencias hipotéticas. Practicas los condicionales mixtos, que conectan una causa pasada con un resultado presente, y usas I wish / if only + past perfect para expresar arrepentimientos sobre el pasado. Al final repasas los tres condicionales (1.º, 2.º y 3.º) en contexto para elegir el correcto según la situación.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
