insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000002301','30000000-0000-0000-0000-000000000023',1,$p$El que y la que: definir personas y cosas$p$,$p$El que y la que: definir personas y cosas$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002302','30000000-0000-0000-0000-000000000023',2,$p$Who, which, that, whose, where$p$,$p$Who, which, that, whose, where$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002303','30000000-0000-0000-0000-000000000023',3,$p$Entre comas: información extra$p$,$p$Entre comas: información extra$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002304','30000000-0000-0000-0000-000000000023',4,$p$Cuándo se puede omitir el relativo$p$,$p$Cuándo se puede omitir el relativo$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002305','30000000-0000-0000-0000-000000000023',5,$p$🏁 Checkpoint Unidad 23$p$,$p$En esta unidad dominas las oraciones de relativo. Usas las especificativas (defining), sin comas, para identificar a quién o a qué te refieres con who (personas), which/that (cosas), whose (posesión) y where (lugares), y construyes definiciones del tipo the person who… / the place where… Distingues las explicativas (non-defining), que van entre comas y solo añaden información extra (sin that). Por último, aprendes a omitir el relativo cuando funciona como objeto del verbo (the film I saw), algo imposible cuando es sujeto.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
