 ('40000000-0000-0000-0000-000000002403','30000000-0000-0000-0000-000000000024',3,$p$Phrasal verbs y colocaciones frecuentes$p$,$p$Phrasal verbs y colocaciones frecuentes$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002404','30000000-0000-0000-0000-000000000024',4,$p$En mi opinión / por otro lado: argumentar$p$,$p$En mi opinión / por otro lado: argumentar$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000002405','30000000-0000-0000-0000-000000000024',5,$p$🏁 Checkpoint Unidad 24$p$,$p$En esta unidad deduces sobre el pasado con modales perfectos: 'must have' (seguridad), 'might/could have' (posibilidad) y 'can't have' (imposibilidad), siempre seguidos de participio. También expresas crítica y arrepentimiento con 'should have' y 'shouldn't have', y la idea de un esfuerzo innecesario con 'needn't have'. Por último, practicas phrasal verbs y colocaciones de uso frecuente y el lenguaje para opinar y argumentar (in my opinion, on the other hand, however).$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
